crystal_doc_search_index_callback({"repository_name":"shards","body":"# Shards\n\n[![CI](https://github.com/crystal-lang/shards/workflows/CI/badge.svg)](https://github.com/crystal-lang/shards/actions?query=workflow%3ACI+event%3Apush+branch%3Amaster)\n\nDependency manager for the [Crystal language](https://crystal-lang.org).\n\n## Usage\n\nCrystal applications and libraries are expected to have a `shard.yml` file\nat their root looking like this:\n\n```yaml\nname: shards\nversion: 0.1.0\n\ndependencies:\n  openssl:\n    github: datanoise/openssl.cr\n    branch: master\n\ndevelopment_dependencies:\n  minitest:\n    git: https://github.com/ysbaddaden/minitest.cr.git\n    version: ~> 0.3.1\n\nlicense: MIT\n```\n\nWhen libraries are installed from Git repositories, the repository is expected\nto have version tags following a [semver](http://semver.org/)-like format,\nprefixed with a `v`. Examples: `v1.2.3`, `v2.0.0-rc1` or `v2017.04.1`.\n\nPlease see the [SPEC](docs/shard.yml.adoc) for more details about the\n`shard.yml` format.\n\n## Install\n\nShards is usually distributed with Crystal itself (e.g. Homebrew and Debian\npackages). Alternatively, a `shards` package may be available for your system.\n\nYou can download a source tarball from the same page (or clone the repository)\nthen run `make release=1`and copy `bin/shards` into your `PATH`. For\nexample `/usr/local/bin`.\n\nYou are now ready to create a `shard.yml` for your projects (see details in\n[SPEC](docs/shard.yml.adoc)). You can type `shards init` to have an example\n`shard.yml` file created for your project.\n\nRun `shards install` to install your dependencies, which will lock your\ndependencies into a `shard.lock` file. You should check both `shard.yml` and\n`shard.lock` into version control, so further `shards install` will always\ninstall locked versions, achieving reproducible installations across computers.\n\nRun `shards --help` to list other commands with their options.\n\nHappy Hacking!\n\n## Developers\n\n### Requirements\n\nThese requirements are only necessary for compiling Shards.\n\n- Crystal\n\n  Please refer to <https://crystal-lang.org/install/> for\n  instructions for your operating system.\n\n- libyaml\n\n  On Debian/Ubuntu Linux you may install the `libyaml-dev` package.\n\n  On Mac OS X you may install it using homebrew with `brew install libyaml`\n  then make sure to have `/usr/local/lib` in your `LIBRARY_PATH` environment\n  variable (eg: `export LIBRARY_PATH=\"/usr/local/lib:$LIBRARY_PATH\"`).\n  Please adjust the path per your Homebrew installation.\n\n- [asciidoctor](https://asciidoctor.org/)\n\n  Needed for building manpages.\n\n### Getting started\n\nIt is strongly recommended to use `make` for building shards and developing it.\nThe [`Makefile`](./Makefile) contains recipes for compiling and testing.\n\nRun `make bin/shards` to build the binary.\n\n- `release=1` for a release build (applies optimizations)\n- `static=1` for static linking (only works with musl-libc)\n- `debug=1` for full symbolic debug info\n\nRun `make install` to install the binary. Target path can be adjusted with `PREFIX` (default: `PREFIX=/usr/bin`).\n\nRun `make test` to run the test suites:\n\n- `make test_unit` runs unit tests (`./spec/unit`)\n- `make test_integration` runs integration tests (`./spec/integration`) on `bin/shards`\n\nRun `make docs` to build the manpages.\n\n### Devenv\n\nThis repository contains a configuration for [devenv.sh](https://devenv.sh) which\nmakes it easy to setup a reproducible environment with all necessary tools for\nbuilding and testing.\n\n- Checkout the repository\n- Run `devenv shell` to get a shell with development environment\n\nA hook for [automatic shell activation](https://devenv.sh/automatic-shell-activation/)\nis also included. If you have `direnv` installed, the devenv environment loads\nautomatically upon entering the repo folder.\n\n## License\n\nLicensed under the Apache License, Version 2.0. See [LICENSE](./LICENSE) for\ndetails.\n","program":{"html_id":"shards/toplevel","path":"toplevel.html","kind":"module","full_name":"Top Level Namespace","name":"Top Level Namespace","abstract":false,"locations":[],"repository_name":"shards","program":true,"enum":false,"alias":false,"const":false,"types":[{"html_id":"shards/Shards","path":"Shards.html","kind":"module","full_name":"Shards","name":"Shards","abstract":false,"locations":[{"filename":"src/versions.cr","line_number":1,"url":null}],"repository_name":"shards","program":false,"enum":false,"alias":false,"const":false,"types":[{"html_id":"shards/Shards/Versions","path":"Shards/Versions.html","kind":"module","full_name":"Shards::Versions","name":"Versions","abstract":false,"locations":[{"filename":"src/versions.cr","line_number":2,"url":null}],"repository_name":"shards","program":false,"enum":false,"alias":false,"const":false,"namespace":{"html_id":"shards/Shards","kind":"module","full_name":"Shards","name":"Shards"},"class_methods":[{"html_id":"compare(a:String,b:String)-class-method","name":"compare","doc":"Compares two version strings to determine their sorting order.\n\nReturns `-1` when *a* is newer than *b*, `1` when *a* is older than *b*,\nand `0` when they are equal. This behavior allows `Shards::Versions.sort`\nto sort arrays of versions in descending order (newest first).\n\n```crystal\nShards::Versions.compare(\"1.0.0\", \"0.9.0\") # => -1\nShards::Versions.compare(\"0.9.0\", \"1.0.0\") # => 1\nShards::Versions.compare(\"1.0.0\", \"1.0.0\") # => 0\n```","summary":"<p>Compares two version strings to determine their sorting order.</p>","abstract":false,"args":[{"name":"a","external_name":"a","restriction":"String"},{"name":"b","external_name":"b","restriction":"String"}],"args_string":"(a : String, b : String)","args_html":"(a : String, b : String)","location":{"filename":"src/versions.cr","line_number":106,"url":null},"def":{"name":"compare","args":[{"name":"a","external_name":"a","restriction":"String"},{"name":"b","external_name":"b","restriction":"String"}],"visibility":"Public","body":"if a == b\n  return 0\nend\n\na_segment = Segment.new(a)\nb_segment = Segment.new(b)\n\nloop do\n\n  a_segment.next\n  b_segment.next\n\n\n  if a_segment.empty?\n    b_segment.only_zeroes? do return b_segment.prerelease? ? -1 : 1 end\n    return 0\n  end\n\n\n  if b_segment.empty?\n    a_segment.only_zeroes? do return a_segment.prerelease? ? 1 : -1 end\n    return 0\n  end\n\n\n  a_num = a_segment.to_i?\n  b_num = b_segment.to_i?\n\n  ret = if a_num && b_num\n    b_num <=> a_num\n  elsif a_num\n    a_segment.only_zeroes? do\n      if a_segment.prerelease?\n        return b_segment <=> a_segment\n      end\n      return -1\n    end\n    return -1\n  elsif b_num\n    b_segment.only_zeroes? do\n      if b_segment.prerelease?\n        return b_segment <=> a_segment\n      end\n      return 1\n    end\n    return 1\n  else\n    b_segment <=> a_segment\n  end\n\n\n\n  if ret == 0\n  else\n    return ret\n  end\nend\n"},"external_var":false},{"html_id":"compare(a:Version,b:Version)-class-method","name":"compare","abstract":false,"args":[{"name":"a","external_name":"a","restriction":"Version"},{"name":"b","external_name":"b","restriction":"Version"}],"args_string":"(a : Version, b : Version)","args_html":"(a : Version, b : Version)","location":{"filename":"src/versions.cr","line_number":91,"url":null},"def":{"name":"compare","args":[{"name":"a","external_name":"a","restriction":"Version"},{"name":"b","external_name":"b","restriction":"Version"}],"visibility":"Public","body":"compare(a.value, b.value)"},"external_var":false},{"html_id":"has_metadata?(str:String)-class-method","name":"has_metadata?","abstract":false,"args":[{"name":"str","external_name":"str","restriction":"String"}],"args_string":"(str : String)","args_html":"(str : String)","location":{"filename":"src/versions.cr","line_number":172,"url":null},"def":{"name":"has_metadata?","args":[{"name":"str","external_name":"str","restriction":"String"}],"visibility":"Public","body":"str.includes?('+')"},"external_var":false},{"html_id":"matches?(version:Version,requirement:VersionReq)-class-method","name":"matches?","abstract":false,"args":[{"name":"version","external_name":"version","restriction":"Version"},{"name":"requirement","external_name":"requirement","restriction":"VersionReq"}],"args_string":"(version : Version, requirement : VersionReq)","args_html":"(version : Version, requirement : VersionReq)","location":{"filename":"src/versions.cr","line_number":184,"url":null},"def":{"name":"matches?","args":[{"name":"version","external_name":"version","restriction":"Version"},{"name":"requirement","external_name":"requirement","restriction":"VersionReq"}],"visibility":"Public","body":"requirement.patterns.all? do |pattern|\n  matches_single_pattern?(version, pattern)\nend"},"external_var":false},{"html_id":"prerelease?(str:String)-class-method","name":"prerelease?","abstract":false,"args":[{"name":"str","external_name":"str","restriction":"String"}],"args_string":"(str : String)","args_html":"(str : String)","location":{"filename":"src/versions.cr","line_number":164,"url":null},"def":{"name":"prerelease?","args":[{"name":"str","external_name":"str","restriction":"String"}],"visibility":"Public","body":"str.each_char do |char|\n  if char.ascii_letter?\n    return true\n  end\n  if char == '+'\n    break\n  end\nend\nfalse\n"},"external_var":false},{"html_id":"resolve(versions:Array(Version),requirement:VersionReq)-class-method","name":"resolve","abstract":false,"args":[{"name":"versions","external_name":"versions","restriction":"Array(Version)"},{"name":"requirement","external_name":"requirement","restriction":"VersionReq"}],"args_string":"(versions : Array(Version), requirement : VersionReq)","args_html":"(versions : Array(Version), requirement : VersionReq)","location":{"filename":"src/versions.cr","line_number":180,"url":null},"def":{"name":"resolve","args":[{"name":"versions","external_name":"versions","restriction":"Array(Version)"},{"name":"requirement","external_name":"requirement","restriction":"VersionReq"}],"visibility":"Public","body":"versions.select do |version| matches?(version, requirement) end"},"external_var":false},{"html_id":"sort(versions)-class-method","name":"sort","abstract":false,"args":[{"name":"versions","external_name":"versions","restriction":""}],"args_string":"(versions)","args_html":"(versions)","location":{"filename":"src/versions.cr","line_number":87,"url":null},"def":{"name":"sort","args":[{"name":"versions","external_name":"versions","restriction":""}],"visibility":"Public","body":"versions.sort do |a, b| compare(a, b) end"},"external_var":false}]}]}]}})